  1→/**
  2→ * Lazily loaded Mermaid instance.
  3→ * Mermaid is dynamically imported to reduce initial content script bundle size.
  4→ * The library (~1 MB) is only loaded when a Mermaid code block is actually detected.
  5→ */
  6→let mermaidInstance: Awaited<typeof import('mermaid')>['default'] | null = null;
  7→let mermaidLoadFailed = false;
  8→
  9→/**
 10→ * Reset internal loader state. Only for testing.
 11→ * @internal
 12→ */
 13→export const _resetMermaidLoader = () => {
 14→  mermaidInstance = null;
 15→  mermaidLoadFailed = false;
 16→};
 17→
 18→/**
 19→ * Dynamically load the Mermaid library.
 20→ * Returns the mermaid default export, or null if loading fails.
 21→ * Once loaded (or failed), the result is cached.
 22→ */
 23→/**
 24→ * @internal Exported for testing
 25→ */
 26→export const loadMermaid = async (): Promise<typeof mermaidInstance> => {
 27→  if (mermaidInstance) return mermaidInstance;
 28→  if (mermaidLoadFailed) return null;
 29→
 30→  try {
 31→    const mod = await import('mermaid');
 32→    mermaidInstance = mod.default;
 33→    return mermaidInstance;
 34→  } catch (error) {
 35→    mermaidLoadFailed = true;
 36→    console.error('[Gemini Voyager] Failed to load Mermaid library:', error);
 37→    return null;
 38→  }
 39→};
 40→
 41→/**
 42→ * Initialize Mermaid configuration
 43→ */
 44→const initMermaid = async (): Promise<boolean> => {
 45→  const mermaid = await loadMermaid();
 46→  if (!mermaid) return false;
 47→
 48→  const isDarkMode =
 49→    document.body.classList.contains('dark-theme') ||
 50→    document.body.getAttribute('data-theme') === 'dark' ||
 51→    document.documentElement.classList.contains('dark') ||
 52→    window.matchMedia('(prefers-color-scheme: dark)').matches;
 53→
 54→  mermaid.initialize({
 55→    startOnLoad: false,
 56→    theme: isDarkMode ? 'dark' : 'default',
 57→    securityLevel: 'loose',
 58→    fontFamily: 'Google Sans, Roboto, sans-serif',
 59→    logLevel: 5, // 5 = fatal, only log fatal errors (v9.x uses numbers)
 60→  });
 61→
 62→  return true;
 63→};
 64→
 65→/**
 66→ * Check if a code block contains Mermaid syntax and appears complete enough to render
 67→ * @internal Exported for testing
 68→ */
 69→export const isMermaidCode = (code: string): boolean => {
 70→  const codeTrimmed = code.trim();
 71→
 72→  // Minimum length to avoid parsing incomplete/streaming content
 73→  if (codeTrimmed.length < 50) return false;
 74→
 75→  // Keywords aligned with mermaid's own detector regexes.
 76→  // Order matters: longer/more-specific prefixes should come before shorter ones
 77→  // so that e.g. "flowchart-elk" isn't matched by "flowchart" and missed.
 78→  const keywords = [
 79→    // Core diagram types (v9+)
 80→    'graph',
 81→    'flowchart',
 82→    'sequenceDiagram',
 83→    'classDiagram',
 84→    'stateDiagram',
 85→    'erDiagram',
 86→    'gantt',
 87→    'pie',
 88→    'gitGraph',
 89→    'journey',
 90→    'mindmap',
 91→    'timeline',
 92→    'zenuml',
 93→    'quadrantChart',
 94→    'requirementDiagram',
 95→    'requirement', // v11: requirement(Diagram)? — shorter form
 96→    'sankey-beta',
 97→    'sankey', // v11: sankey(-beta)?
 98→    // C4 diagrams (v9+, often overlooked)
 99→    'C4Context',
100→    'C4Container',
101→    'C4Component',
102→    'C4Dynamic',
103→    'C4Deployment',
104→    // New diagram types (v10+/v11+, Chrome/Safari)
105→    'xychart-beta',
106→    'xychart', // v11: xychart(-beta)?
107→    'block-beta',
108→    'block', // v11: block(-beta)?
109→    'packet-beta',
110→    'packet', // v11: packet(-beta)?
111→    'architecture-beta',
112→    'architecture', // v11: architecture(-beta)?
113→    'kanban',
114→    'radar-beta', // v11
115→    'treemap', // v11
116→  ];
117→
118→  const startsWithKeyword =
119→    codeTrimmed.startsWith('%%') ||
120→    keywords.some((keyword) => codeTrimmed.toLowerCase().startsWith(keyword.toLowerCase()));
121→
122→  if (!startsWithKeyword) return false;
123→
124→  // Check if code looks complete (has multiple lines and doesn't end mid-statement)
125→  const lines = codeTrimmed.split('\n').filter((l) => l.trim().length > 0);
126→  if (lines.length < 3) return false;
127→
128→  // Check last line doesn't look incomplete (ending with operators or open brackets)
129→  const lastLine = lines[lines.length - 1].trim();
130→  const incompleteEndings = ['-->', '---', '-.', '==>', ':::', '[', '(', '{', '|', '&', ','];
131→  if (incompleteEndings.some((ending) => lastLine.endsWith(ending))) return false;
132→
133→  return true;
134→};
