275→/**
276→ * Fullscreen viewer state
277→ */
278→let currentModal: HTMLElement | null = null;
279→let scale = 1;
280→let translateX = 0;
281→let translateY = 0;
282→let isDragging = false;
283→let startX = 0;
284→let startY = 0;
285→
286→/**
287→ * Open fullscreen viewer for SVG
288→ */
289→const openFullscreen = (svgHtml: string) => {
290→  if (currentModal) return;
291→
292→  // Reset state
293→  scale = 1;
294→  translateX = 0;
295→  translateY = 0;
296→
297→  // Create modal
298→  const modal = document.createElement('div');
299→  modal.className = 'gv-mermaid-modal';
300→
301→  // Toolbar
302→  const toolbar = document.createElement('div');
303→  toolbar.className = 'gv-mermaid-modal-toolbar';
304→
305→  const zoomInBtn = document.createElement('button');
306→  zoomInBtn.innerHTML = '+';
307→  zoomInBtn.title = 'Zoom In';
308→
309→  const zoomOutBtn = document.createElement('button');
310→  zoomOutBtn.innerHTML = '−';
311→  zoomOutBtn.title = 'Zoom Out';
312→
313→  const resetBtn = document.createElement('button');
314→  resetBtn.innerHTML = '⊙';
315→  resetBtn.title = 'Reset';
316→
317→  const closeBtn = document.createElement('button');
318→  closeBtn.innerHTML = '✕';
319→  closeBtn.title = 'Close (ESC)';
320→
321→  toolbar.appendChild(zoomInBtn);
322→  toolbar.appendChild(zoomOutBtn);
323→  toolbar.appendChild(resetBtn);
324→  toolbar.appendChild(closeBtn);
325→
326→  // Content container
327→  const content = document.createElement('div');
328→  content.className = 'gv-mermaid-modal-content';
329→  content.innerHTML = svgHtml;
330→
331→  // Hint
332→  const hint = document.createElement('div');
333→  hint.className = 'gv-mermaid-modal-hint';
334→  hint.textContent = 'Scroll to zoom • Drag to pan • ESC to close';
335→
336→  modal.appendChild(toolbar);
337→  modal.appendChild(content);
338→  modal.appendChild(hint);
339→  document.body.appendChild(modal);
340→  currentModal = modal;
341→
342→  // Apply transform
343→  const applyTransform = () => {
344→    content.style.transform = `translate(${translateX}px, ${translateY}px) scale(${scale})`;
345→  };
346→
347→  // Zoom functions
348→  const zoomIn = () => {
349→    scale = Math.min(scale * 1.2, 10);
350→    applyTransform();
351→  };
352→
353→  const zoomOut = () => {
354→    scale = Math.max(scale / 1.2, 0.1);
355→    applyTransform();
356→  };
357→
358→  const resetView = () => {
359→    scale = 1;
360→    translateX = 0;
361→    translateY = 0;
362→    applyTransform();
363→  };
364→
365→  const closeModal = () => {
366→    modal.classList.remove('visible');
367→    setTimeout(() => {
368→      modal.remove();
369→      currentModal = null;
370→    }, 300);
371→  };
372→
373→  // Event listeners
374→  zoomInBtn.addEventListener('click', zoomIn);
375→  zoomOutBtn.addEventListener('click', zoomOut);
376→  resetBtn.addEventListener('click', resetView);
377→  closeBtn.addEventListener('click', closeModal);
378→
379→  // Click backdrop to close
380→  modal.addEventListener('click', (e) => {
381→    if (e.target === modal) closeModal();
382→  });
383→
384→  // ESC to close
385→  const handleKeyDown = (e: KeyboardEvent) => {
386→    if (e.key === 'Escape') {
387→      closeModal();
388→      document.removeEventListener('keydown', handleKeyDown);
389→    }
390→  };
391→  document.addEventListener('keydown', handleKeyDown);
392→
393→  // Mouse wheel zoom
394→  modal.addEventListener(
395→    'wheel',
396→    (e) => {
397→      e.preventDefault();
398→      if (e.deltaY < 0) {
399→        scale = Math.min(scale * 1.1, 10);
400→      } else {
401→        scale = Math.max(scale / 1.1, 0.1);
402→      }
403→      applyTransform();
404→    },
405→    { passive: false },
406→  );
407→
408→  // Drag to pan
409→  content.addEventListener('mousedown', (e) => {
410→    isDragging = true;
411→    startX = e.clientX - translateX;
412→    startY = e.clientY - translateY;
413→    content.classList.add('dragging');
414→  });
415→
416→  document.addEventListener('mousemove', (e) => {
417→    if (!isDragging) return;
418→    translateX = e.clientX - startX;
419→    translateY = e.clientY - startY;
420→    applyTransform();
421→  });
422→
423→  document.addEventListener('mouseup', () => {
424→    isDragging = false;
425→    content.classList.remove('dragging');
426→  });
427→
428→  // Show modal with animation
429→  requestAnimationFrame(() => {
430→    modal.classList.add('visible');
431→  });
432→};
