434→/**
435→ * Normalize whitespace characters in Mermaid code
436→ * Replaces non-breaking spaces (NBSP \u00A0) and other special whitespace
437→ * with standard spaces to prevent Mermaid parsing errors.
438→ *
439→ * Common problematic characters:
440→ * - \u00A0 (NBSP): From web pages, Word, Notion, WeChat, etc.
441→ * - \u2003 (Em Space)
442→ * - \u2002 (En Space)
443→ * - \u2009 (Thin Space)
444→ * - \u200B (Zero-width Space)
445→ * - \u3000 (Ideographic Space - CJK full-width space)
446→ */
447→/**
448→ * @internal Exported for testing
449→ */
450→export const normalizeWhitespace = (code: string): string => {
451→  return (
452→    code
453→      // Replace various special space characters with standard space
454→      .replace(/[\u00A0\u2002\u2003\u2009\u3000]/g, ' ')
455→      // Remove zero-width characters that can cause issues
456→      .replace(/[\u200B\u200C\u200D\uFEFF]/g, '')
457→  );
458→};
459→
460→/**
461→ * Render Mermaid diagram for a code block
462→ */
463→const renderMermaid = async (codeBlock: HTMLElement, code: string) => {
464→  // Normalize whitespace before processing
465→  const normalizedCode = normalizeWhitespace(code);
466→  if (codeBlock.dataset.mermaidCode === normalizedCode) return;
467→  if (codeBlock.dataset.mermaidProcessing === 'true') return;
468→
469→  codeBlock.dataset.mermaidProcessing = 'true';
470→
471→  try {
472→    const codeBlockHost = codeBlock.closest('code-block') as HTMLElement;
473→    if (!codeBlockHost) {
474→      codeBlock.dataset.mermaidProcessing = 'false';
475→      return;
476→    }
477→
478→    // Ensure Mermaid is loaded before rendering
479→    const mermaid = await loadMermaid();
480→    if (!mermaid) {
481→      // Mermaid failed to load — gracefully degrade by showing raw code
482→      codeBlock.dataset.mermaidProcessing = 'false';
483→      return;
484→    }
485→
486→    // First, try to render to validate the code
487→    const uniqueId = `mermaid-${Math.random().toString(36).substr(2, 9)}`;
488→    let svg: string;
489→
490→    try {
491→      // v9.x render returns string directly, v10.x returns {svg: string}
492→      const result = await mermaid.render(uniqueId, normalizedCode);
493→      svg = typeof result === 'string' ? result : (result as { svg: string }).svg;
494→    } catch (renderError) {
495→      // Mermaid failed - likely incomplete or invalid syntax
496→
497→      // Clean up any error SVGs mermaid may have created
498→      const errorSvg = document.getElementById(uniqueId);
499→      if (errorSvg) errorSvg.remove();
500→
501→      // Also clean up any floating error containers mermaid creates
502→      document.querySelectorAll('[id^="d"]').forEach((el) => {
503→        if (el.textContent?.includes('Syntax error') || el.querySelector('.error-icon')) {
504→          el.remove();
505→        }
506→      });
507→
508→      // Create a friendly error message
509→      const errorMsg = renderError instanceof Error ? renderError.message : 'Unknown error';
510→      const shortError = errorMsg.length > 100 ? errorMsg.substring(0, 100) + '...' : errorMsg;
511→      svg = `
512→                <div style="padding: 24px; text-align: center; color: var(--gemini-on-surface-variant, #666);">
513→                    <div style="font-size: 32px; margin-bottom: 12px;">⚠️</div>
514→                    <div style="font-weight: 500; margin-bottom: 8px;">Mermaid Syntax Error</div>
515→                    <div style="font-size: 12px; opacity: 0.7; font-family: monospace; max-width: 400px; margin: 0 auto; word-break: break-word;">${shortError}</div>
516→                    <div style="margin-top: 12px; font-size: 13px;">Click <b>"&lt;/&gt; Code"</b> to view source</div>
517→                </div>
518→            `;
519→    }
520→
521→    // Rendering succeeded! Now create or update the UI
522→    let wrapper = codeBlockHost.parentElement;
523→    if (!wrapper?.classList.contains('gv-mermaid-wrapper')) {
524→      wrapper = document.createElement('div');
525→      wrapper.className = 'gv-mermaid-wrapper';
526→      codeBlockHost.parentElement?.insertBefore(wrapper, codeBlockHost);
527→      wrapper.appendChild(codeBlockHost);
528→
529→      // Toggle buttons
530→      const toggleContainer = document.createElement('div');
531→      toggleContainer.className = 'gv-mermaid-toggle';
532→
533→      // Try to find and move the native copy button to our toolbar
534→      // This prevents overlap/covering issues and keeps the UI clean
535→      // We look for .buttons container (newer Gemini) or .copy-button class
536→      const parentElement = wrapper?.parentElement || codeBlockHost.parentElement;
537→      const nativeCopyBtn =
538→        parentElement?.querySelector('.buttons') || parentElement?.querySelector('.copy-button');
539→
540→      // Only move if it looks like the right button (close to the code block)
541→      if (nativeCopyBtn) {
542→        // Reset positioning that might conflict
543→        (nativeCopyBtn as HTMLElement).style.position = 'static';
544→        (nativeCopyBtn as HTMLElement).style.top = 'auto';
545→        (nativeCopyBtn as HTMLElement).style.right = 'auto';
546→        (nativeCopyBtn as HTMLElement).style.marginTop = '0';
547→        toggleContainer.appendChild(nativeCopyBtn);
548→      }
549→
550→      const diagramBtn = document.createElement('button');
551→      diagramBtn.textContent = '📊 Diagram';
552→      diagramBtn.className = 'active';
553→      diagramBtn.dataset.view = 'diagram';
554→
555→      const codeBtn = document.createElement('button');
556→      codeBtn.textContent = '</> Code';
557→      codeBtn.dataset.view = 'code';
558→
559→      toggleContainer.appendChild(diagramBtn);
560→      toggleContainer.appendChild(codeBtn);
561→      wrapper.appendChild(toggleContainer);
562→
563→      // Diagram container
564→      const diagramContainer = document.createElement('div');
565→      diagramContainer.className = 'gv-mermaid-diagram';
566→      wrapper.appendChild(diagramContainer);
567→
568→      codeBlockHost.style.display = 'none';
569→
570→      const updateView = (view: 'diagram' | 'code') => {
571→        if (view === 'diagram') {
572→          codeBlockHost.style.display = 'none';
573→          diagramContainer.style.display = 'block';
574→          diagramBtn.classList.add('active');
575→          codeBtn.classList.remove('active');
576→        } else {
577→          codeBlockHost.style.display = '';
578→          diagramContainer.style.display = 'none';
579→          diagramBtn.classList.remove('active');
580→          codeBtn.classList.add('active');
581→        }
582→      };
583→
584→      diagramBtn.addEventListener('click', () => updateView('diagram'));
585→      codeBtn.addEventListener('click', () => updateView('code'));
586→
587→      // Click diagram to fullscreen (only if it's a valid SVG, not error)
588→      diagramContainer.addEventListener('click', () => {
589→        const svgElement = diagramContainer.querySelector('svg');
590→        if (svgElement) {
591→          openFullscreen(diagramContainer.innerHTML);
592→        }
593→      });
594→    }
595→
596→    const diagramContainer = wrapper.querySelector('.gv-mermaid-diagram') as HTMLElement;
597→    if (!diagramContainer) {
598→      codeBlock.dataset.mermaidProcessing = 'false';
599→      return;
600→    }
601→
602→    // Insert the successfully rendered SVG
603→    diagramContainer.innerHTML = svg;
604→
605→    codeBlock.dataset.mermaidCode = normalizedCode;
606→    codeBlock.dataset.mermaidProcessing = 'false';
607→    console.log('[Gemini Voyager] Mermaid diagram rendered:', uniqueId);
608→  } catch {
609→    codeBlock.dataset.mermaidProcessing = 'false';
610→
611→    const codeBlockHost = codeBlock.closest('code-block') as HTMLElement;
612→    if (codeBlockHost) {
613→      codeBlockHost.style.display = '';
614→    }
615→  }
616→};
