618→/**
619→ * Get the language label from a code block's header decoration
620→ * Returns the language name (lowercase) or null if not found
621→ */
622→const getCodeBlockLanguage = (codeEl: Element): string | null => {
623→  // Navigate up to find the code-block container
624→  const codeBlock = codeEl.closest('.code-block, code-block');
625→  if (!codeBlock) return null;
626→
627→  // Look for the language label in the header decoration
628→  // Gemini uses: <div class="code-block-decoration"><span>Language</span>...</div>
629→  const decoration = codeBlock.querySelector('.code-block-decoration');
630→  if (!decoration) return null;
631→
632→  // The first span child typically contains the language name
633→  const langSpan = decoration.querySelector(':scope > span');
634→  if (!langSpan) return null;
635→
636→  const language = langSpan.textContent?.trim().toLowerCase();
637→  return language || null;
638→};
