640→/**
641→ * Generic/non-specific language labels that should still allow Mermaid detection
642→ * These are labels that don't represent a specific programming language
643→ */
644→const GENERIC_LANGUAGE_LABELS = new Set([
645→  // Chinese
646→  '代码段',
647→  '代码',
648→  '代码块',
649→  '示例',
650→  '示例代码',
651→  // English
652→  'code',
653→  'code snippet',
654→  'snippet',
655→  'example',
656→  'code example',
657→  'sample',
658→  // Common generic terms
659→  'text',
660→  'plain',
661→  'plaintext',
662→  'raw',
663→  'output',
664→  'result',
665→]);
666→
667→/**
668→ * Check if a language label is generic (not a specific programming language)
669→ */
670→/**
671→ * @internal Exported for testing
672→ */
673→export const isGenericLanguageLabel = (language: string | null): boolean => {
674→  if (!language) return true; // No label = generic
675→  return GENERIC_LANGUAGE_LABELS.has(language.toLowerCase());
676→};
677→
678→/**
679→ * Find and process code blocks
680→ */
681→const processCodeBlocks = () => {
682→  const codeElements = document.querySelectorAll('code[data-test-id="code-content"]');
683→
684→  codeElements.forEach((codeEl) => {
685→    const codeText = codeEl.textContent || '';
686→
687→    // Check the language label from Gemini's code block header
688→    const language = getCodeBlockLanguage(codeEl);
689→
690→    // Case 1: Language is explicitly "mermaid" - always render
691→    if (language === 'mermaid') {
692→      renderMermaid(codeEl as HTMLElement, codeText);
693→      return;
694→    }
695→
696→    // Case 2: Language is a specific programming language (not generic) - skip rendering
697→    // This prevents false positives for MATLAB (%% comments), Python, etc.
698→    if (language && !isGenericLanguageLabel(language)) {
699→      return;
700→    }
701→
702→    // Case 3: No language label or generic label - use content detection
703→    if (isMermaidCode(codeText)) {
704→      renderMermaid(codeEl as HTMLElement, codeText);
705→    }
706→  });
707→};
708→
709→/**
710→ * Track whether Mermaid is enabled
711→ */
712→let mermaidEnabled = true;
713→let observer: MutationObserver | null = null;
714→
715→/**
716→ * Start Mermaid feature
717→ */
718→export const startMermaid = () => {
719→  // Check if Mermaid rendering is enabled in settings
720→  chrome.storage?.sync?.get({ gvMermaidEnabled: true }, (result) => {
721→    mermaidEnabled = result?.gvMermaidEnabled !== false;
722→
723→    if (mermaidEnabled) {
724→      initializeMermaid();
725→    } else {
726→      console.log('[Gemini Voyager] Mermaid rendering is disabled');
727→    }
728→  });
729→
730→  // Listen for setting changes
731→  chrome.storage?.onChanged?.addListener((changes, areaName) => {
732→    if (areaName === 'sync' && changes.gvMermaidEnabled) {
733→      mermaidEnabled = changes.gvMermaidEnabled.newValue !== false;
734→      if (mermaidEnabled) {
735→        initializeMermaid();
736→        console.log('[Gemini Voyager] Mermaid rendering enabled');
737→      } else {
738→        // Stop observing when disabled
739→        if (observer) {
740→          observer.disconnect();
741→          observer = null;
742→        }
743→        console.log('[Gemini Voyager] Mermaid rendering disabled');
744→      }
745→    }
746→  });
747→};
748→
749→/**
750→ * Initialize Mermaid rendering
751→ */
752→const initializeMermaid = async () => {
753→  createStyles();
754→
755→  const loaded = await initMermaid();
756→  if (!loaded) {
757→    console.warn('[Gemini Voyager] Mermaid library failed to load, diagrams will show as code');
758→    return;
759→  }
760→
761→  processCodeBlocks();
762→
763→  // Only create observer if not already exists
764→  if (!observer) {
765→    let timeout: ReturnType<typeof setTimeout>;
766→    const debouncedProcess = () => {
767→      if (!mermaidEnabled) return;
768→      clearTimeout(timeout);
769→      timeout = setTimeout(processCodeBlocks, 1000);
770→    };
771→
772→    observer = new MutationObserver(() => {
773→      debouncedProcess();
774→    });
775→
776→    observer.observe(document.body, {
777→      childList: true,
778→      subtree: true,
779→      characterData: true,
780→    });
781→  }
782→
783→  console.log('[Gemini Voyager] Mermaid integration started');
784→};
