let startX = 0;          // Mouse down X
let startY = 0;          // Mouse down Y
```

#### **C. Zoom Controls** (lines 348-356)
```typescript
const zoomIn = () => {
  scale = Math.min(scale * 1.2, 10);   // Cap at 10x
  applyTransform();
};

const zoomOut = () => {
  scale = Math.max(scale / 1.1, 0.1);  // Floor at 0.1x
  applyTransform();
};

const resetView = () => {
  scale = 1;
  translateX = 0;
  translateY = 0;
  applyTransform();
};
```

#### **D. Pan/Drag Interaction** (lines 408-426)
```typescript
// Mouse down: Start drag
content.addEventListener('mousedown', (e) => {
  isDragging = true;
  startX = e.clientX - translateX;  // Subtract current position
  startY = e.clientY - translateY;
  content.classList.add('dragging');  // Cursor: grabbing
});

// Mouse move: Update position
document.addEventListener('mousemove', (e) => {
  if (!isDragging) return;
  translateX = e.clientX - startX;
  translateY = e.clientY - startY;
  applyTransform();
});

// Mouse up: Stop drag
document.addEventListener('mouseup', () => {
  isDragging = false;
  content.classList.remove('dragging');
});
```

**Transform applied**:
