/**
 * Fullscreen viewer state
 */
let currentModal: HTMLElement | null = null;
let scale = 1;
let translateX = 0;
let translateY = 0;
let isDragging = false;
let startX = 0;
let startY = 0;

/**
 * Open fullscreen viewer for SVG
 */
const openFullscreen = (svgHtml: string) => {
  if (currentModal) return;

  // Reset state
  scale = 1;
  translateX = 0;
  translateY = 0;

  // Create modal
  const modal = document.createElement('div');
  modal.className = 'gv-mermaid-modal';

  // Toolbar
  const toolbar = document.createElement('div');
  toolbar.className = 'gv-mermaid-modal-toolbar';

  const zoomInBtn = document.createElement('button');
  zoomInBtn.innerHTML = '+';
  zoomInBtn.title = 'Zoom In';

  const zoomOutBtn = document.createElement('button');
  zoomOutBtn.innerHTML = '−';
  zoomOutBtn.title = 'Zoom Out';

  const resetBtn = document.createElement('button');
  resetBtn.innerHTML = '⊙';
  resetBtn.title = 'Reset';

  const closeBtn = document.createElement('button');
  closeBtn.innerHTML = '✕';
  closeBtn.title = 'Close (ESC)';

  toolbar.appendChild(zoomInBtn);
  toolbar.appendChild(zoomOutBtn);
  toolbar.appendChild(resetBtn);
  toolbar.appendChild(closeBtn);

  // Content container
  const content = document.createElement('div');
  content.className = 'gv-mermaid-modal-content';
  content.innerHTML = svgHtml;

  // Hint
  const hint = document.createElement('div');
  hint.className = 'gv-mermaid-modal-hint';
  hint.textContent = 'Scroll to zoom • Drag to pan • ESC to close';

  modal.appendChild(toolbar);
  modal.appendChild(content);
  modal.appendChild(hint);
  document.body.appendChild(modal);
  currentModal = modal;

  // Apply transform
  const applyTransform = () => {
    content.style.transform = `translate(${translateX}px, ${translateY}px) scale(${scale})`;
  };

  // Zoom functions
  const zoomIn = () => {
    scale = Math.min(scale * 1.2, 10);
    applyTransform();
  };

  const zoomOut = () => {
    scale = Math.max(scale / 1.2, 0.1);
    applyTransform();
  };

  const resetView = () => {
    scale = 1;
    translateX = 0;
    translateY = 0;
    applyTransform();
  };

  const closeModal = () => {
    modal.classList.remove('visible');
    setTimeout(() => {
      modal.remove();
      currentModal = null;
    }, 300);
  };

  // Event listeners
  zoomInBtn.addEventListener('click', zoomIn);
  zoomOutBtn.addEventListener('click', zoomOut);
  resetBtn.addEventListener('click', resetView);
  closeBtn.addEventListener('click', closeModal);

  // Click backdrop to close
  modal.addEventListener('click', (e) => {
    if (e.target === modal) closeModal();
  });

  // ESC to close
  const handleKeyDown = (e: KeyboardEvent) => {
    if (e.key === 'Escape') {
      closeModal();
      document.removeEventListener('keydown', handleKeyDown);
    }
  };
  document.addEventListener('keydown', handleKeyDown);

  // Mouse wheel zoom
  modal.addEventListener(
    'wheel',
    (e) => {
      e.preventDefault();
      if (e.deltaY < 0) {
        scale = Math.min(scale * 1.1, 10);
      } else {
        scale = Math.max(scale / 1.1, 0.1);
      }
      applyTransform();
    },
    { passive: false },
  );

  // Drag to pan
  content.addEventListener('mousedown', (e) => {
    isDragging = true;
    startX = e.clientX - translateX;
    startY = e.clientY - translateY;
    content.classList.add('dragging');
  });

  document.addEventListener('mousemove', (e) => {
    if (!isDragging) return;
    translateX = e.clientX - startX;
    translateY = e.clientY - startY;
    applyTransform();
  });

  document.addEventListener('mouseup', () => {
    isDragging = false;
    content.classList.remove('dragging');
  });

  // Show modal with animation
  requestAnimationFrame(() => {
    modal.classList.add('visible');
  });
};

/**
 * Normalize whitespace characters in Mermaid code
 * Replaces non-breaking spaces (NBSP \u00A0) and other special whitespace
 * with standard spaces to prevent Mermaid parsing errors.
 *
 * Common problematic characters:
 * - \u00A0 (NBSP): From web pages, Word, Notion, WeChat, etc.
 * - \u2003 (Em Space)
 * - \u2002 (En Space)
 * - \u2009 (Thin Space)
 * - \u200B (Zero-width Space)

